import React from 'react';
import { Card, CardContent, Typography, Box, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Headline {
  title: string;
  source: string;
  timeAgo: string;
}

interface NewsData {
  headlines: Headline[];
}

export default function Widget() {
  const newsData = response.data as NewsData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 300, maxWidth: 400, bgcolor: '#FFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} color="text.primary">
            News Headlines
          </Typography>
          <Stack spacing={1}>
            {newsData.headlines.map((headline, index) => (
              <Box key={index}>
                <Typography variant="body1" fontWeight={500} sx={{ mb: 0.5 }}>
                  {headline.title}
                </Typography>
                <Stack direction="row" spacing={0.5}>
                  <Chip label={headline.source} sx={{ fontSize: '11px', px: 1, py: 0.5 }} />
                  <Typography variant="caption" color="text.secondary">
                    {headline.timeAgo}
                  </Typography>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
